<template>
  <div>
    <Navbar/>
    <Alert/>
    <div class="container-fluid">
      <div class="row">
        <Sidebar></Sidebar>
        <main role="main" class="col-md-9 ml-sm-auto col-lg-10 px-4">
          <router-view></router-view>
        </main>
      </div>
    </div>
  </div>
</template>

<script>
import Sidebar from '@/components/backPage/Sidebar.vue';
import Navbar from '@/components/backPage/Navbar.vue';
import Alert from '@/components/backPage/AlertMessage.vue';

export default {
  components: {
    Sidebar,
    Navbar,
    Alert,
  },
  created() {
    const token = document.cookie.replace(/(?:(?:^|.*;\s*)hexAPIToken\s*=\s*([^;]*).*$)|^.*$/, '$1');
    this.$http.defaults.headers.common.Authorization = `${token}`;
  },
};
</script>
